<?php
 namespace WPAICG\Core\Stream\Vector\BuildContext; use WPAICG\Core\AIPKit_AI_Caller; use WP_Error; if (!defined('ABSPATH')) { exit; } function resolve_embedding_vector_logic( AIPKit_AI_Caller $ai_caller, string $user_message, string $embedding_provider_normalized, string $embedding_model ): array|\WP_Error { $embedding_options = ['model' => $embedding_model]; $embedding_result = $ai_caller->generate_embeddings($embedding_provider_normalized, $user_message, $embedding_options); if (is_wp_error($embedding_result) || empty($embedding_result['embeddings'][0])) { $error_message = is_wp_error($embedding_result) ? $embedding_result->get_error_message() : 'No embeddings returned.'; return new WP_Error('embedding_failed_for_query', $error_message); } return $embedding_result['embeddings'][0]; } 